script:
# 1. The Bi-directional Swap Map
def get_replacements: {
  "LCTRL": "LGUI",
  "RCTRL": "RGUI",
  "LGUI": "LCTRL",
  "RGUI": "RCTRL",
  "LC": "LG",
  "RC": "RG",
  "LG": "LC",
  "RG": "RC"
};

# 2. The Universal Walker
# This targets every object with a 'value' key anywhere in the file
def for_every_binding(f):
  (.. | objects | select(has("value"))) |= f;

# PASS 1: The Specific LC(Y) Exception
# Using a structural check to catch nested LC -> Y
def pass_1_exception:
  if .value == "LC" and (.params[0].value == "Y") then
    .value = "LG"
    | .params[0] = {
        "value": "LS",
        "params": [{ "value": "Z", "params": [] }]
      }
  else . end;

# PASS 2: The Global Recursive Modifier Swap
def pass_2_swap($r):

  # Protect the result of Pass 1 from being swapped back
  if .value == "LG"
     and .params[0].value == "LS"
     and .params[0].params[0].value == "Z"
  then
    .

  else
    .value |= (
      if type == "string" then
        if startswith("LC(") then sub("LC\\("; "LG(")
        elif startswith("LG(") then sub("LG\\("; "LC(")
        elif startswith("RC(") then sub("RC\\("; "RG(")
        elif startswith("RG(") then sub("RG\\("; "RC(")
        else ($r[.] // .)
        end
      else .
      end
    )
  end;

# --- EXECUTION ---
get_replacements as $r |
for_every_binding(pass_1_exception) |
for_every_binding(pass_2_swap($r))

# Modifier sequences
{
  "GACS": [
    "LGUI", "LALT", "LCTRL", "LSHFT",
    "RSHFT", "RCTRL", "LALT", "RGUI"
  ],
  "CAGS": [
    "LCTRL", "LALT", "LGUI", "LSHFT",
    "RSHFT", "RGUI", "LALT", "RCTRL"
  ]
} as $mod_registry |

# ==============================================================================
# 1. CORE UTILITIES
# ==============================================================================

def log_err($msg):
  ($msg | stderr) | empty;

def get_side($idx):
  if $idx < 4 then "left" else "right" end;

# Robust node extraction (string/object/null safe)
def get_char_node:
  if type == "object" then
    (.params[1] // .params[0] // { value: "NONE", params: [] })
  elif type == "string" then
    { value: ., params: [] }
  else
    { value: "NONE", params: [] }
  end;

# ==============================================================================
# 2. DATA REGISTRY
# ==============================================================================

def GetRegistry($v):
  {
    "1": {
      flavor: "balanced",
      idle: 150,
      naming: "simple",
      profiles: [
        { id: "hand", term: 280, quick: 175 }
      ],
      map: [
        "hand","hand","hand","hand",
        "hand","hand","hand","hand"
      ]
    },

    "2": {
      flavor: "balanced",
      idle: 150,
      naming: "HRM",
      profiles: [
        { id: "finger", term: 250, quick: 105 },
        { id: "index",  term: 200, quick: 150 }
      ],
      map: [
        "finger","finger","finger","index",
        "index","finger","finger","finger"
      ]
    },

    "3": {
      flavor: "tap-preferred",
      idle: 150,
      naming: "HRM",
      profiles: [
        { id: "pinky", term: 270, quick: 300 },
        { id: "ring",  term: 240, quick: 300 },
        { id: "middy", term: 210, quick: 300 },
        { id: "index", term: 180, quick: 300, idle: 100 }
      ],
      map: [
        "pinky","ring","middy","index",
        "index","middy","ring","pinky"
      ]
    }
  }[$v | tostring]
  // (log_err("FATAL: Version \\($v) not found") | halt);

# ==============================================================================
# 3. HARDWARE ABSTRACTION LAYER (HAL)
# ==============================================================================

def GetHardware:
  (.layout.keys | length) as $len |
  if $len > 70 then
    { type: "glove80", home: [35,36,37,38,41,42,43,44], l_pref: "R_C", r_pref: "L_C" }
  elif $len > 0 then
    { type: "go60", home: [25,26,27,28,31,32,33,34], l_pref: "R_C", r_pref: "L_C" }
  else
    log_err("FATAL: Layout empty") | halt
  end;

# ==============================================================================
# 4. MAIN TRANSFORMATION ENGINE
# ==============================================================================

(GetRegistry($target_version)) as $cfg |
(GetHardware) as $hw |
($mod_registry[$mod_preset] // $mod_registry["GACS"]) as $mod_seq |

# ----------------------------------------------------------------------
# STAGE 1: Positional Indexing
# ----------------------------------------------------------------------

(.layout.keys | reduce .[] as $k (
  { l_trigs: [], r_trigs: [], home_map: {} };

  ($k.label // "") as $lbl |

  (if ($lbl | startswith($hw.l_pref)) then .l_trigs += [$k.i] else . end) |
  (if ($lbl | startswith($hw.r_pref)) then .r_trigs += [$k.i] else . end) |

  ($hw.home | index($k.i)) as $idx |
  (if $idx != null then .home_map[$k.i | tostring] = $idx else . end)
)) as $db |

# ----------------------------------------------------------------------
# STAGE 2: Apply Transformation
# ----------------------------------------------------------------------

(.keymap // .) |= (

  .holdTaps = (
    [
      (.holdTaps // [])[],

      (("left","right") as $side |
        $cfg.profiles[] | {
          name:
            (if $cfg.naming == "simple"
             then "&\\($side)_hand"
             else "&HRM_\\($side)_\\(.id)" end),

          description: "Auto-gen \\($side) HRM (v\\($target_version))",
          bindings: ["&kp","&kp"],
          tappingTermMs: .term,
          quickTapMs: .quick,
          requirePriorIdleMs: (.idle // $cfg.idle),
          flavor: $cfg.flavor,
          holdTriggerOnRelease: true,

          holdTriggerKeyPositions:
            (if $side == "left"
             then ($db.l_trigs | sort)
             else ($db.r_trigs | sort)
             end)
        }
      )
    ] | unique_by(.name)
  ) |

  .layers[0] |= [
    range(length) as $i | .[$i] |
    ($db.home_map[$i | tostring]) as $h_idx |

    if $h_idx != null then
      get_side($h_idx) as $side |
      get_char_node as $char |

      (if $preserve_decorators
       and type == "object"
       and .decoration
       then { decoration: .decoration }
       else {}
       end) as $dec |

      {
        value:
          (if $cfg.naming == "simple"
           then "&\\($side)_hand"
           else "&HRM_\\($side)_\\($cfg.map[$h_idx])"
           end),

        params: [
          { value: $mod_seq[$h_idx], params: [] },
          $char
        ]
      } + $dec

    else . end
  ]
)

# 1. Set your configuration variables (keeps the AST root context clean)
"my_macro_string" as $macro_id |
"Helloworld@!1" as $macro_string |

# 2. Generate the new macro object
(
  {
    "name": "&\($macro_id)",
    "description": "Print \"\($macro_string)\"",
    "bindings": (
      $macro_string | split("") | map(
        if test("^[A-Z]$") then
          {
            "value": "&kp",
            "params": [
              {
                "value": "LS",
                "params": [
                  {
                    "value": .,
                    "params": []
                  }
                ]
              }
            ]
          }
        elif test("^[0-9]$") then
          {
            "value": "&kp",
            "params": [
              {
                "value": ("N" + .),
                "params": []
              }
            ]
          }
        else
          {
            "value": "&kp",
            "params": [
              {
                "value": (. | ascii_upcase),
                "params": []
              }
            ]
          }
        end
      )
    ),
    "params": []
  }
) as $new_macro |

# 3. Safely inject into the AST
"&\($macro_id)" as $macro_name |

# Safely grab the macros array, defaulting to an empty array if it doesn't exist yet
(.keymap.macros // []) as $existing_macros |
($existing_macros | map(.name) | index($macro_name)) as $idx |

# Update if it exists, append if it's new
if $idx != null then
  .keymap.macros[$idx] = $new_macro
else
  .keymap.macros = $existing_macros + [$new_macro]
end

# ZMK Autonomous Injection Script (V5.1) - "The Full Listener Engine"
# Strategy: Dynamic Creation + Comprehensive Listener Injection

(if .keymap then .keymap else . end) |= (

  # --- STEP 1: INITIALIZE NAMES & LAYERS ---
  ["Mouse", "MouseSlow", "MouseFast", "MouseWarp"] as $required |

  .layer_names |= (if . == null then [] else . end) |
  .layers |= (if . == null then [] else . end) |

  reduce $required[] as $name (.;
    if (.layer_names | index($name) == null) then
      .layer_names += [$name] |
      .layers += [[range(60) | {"value": "&trans", "params": []}]]
    else .
    end
  ) |

  # --- STEP 2: RESOLVE DYNAMIC INDICES ---
  (.layer_names | index("Mouse")) as $idx_mouse |
  (.layer_names | index("MouseSlow")) as $idx_slow |
  (.layer_names | index("MouseFast")) as $idx_fast |
  (.layer_names | index("MouseWarp")) as $idx_warp |

  # --- STEP 3: KEYMAP INJECTION ---
  .layers[0][58] = {
    "value": "&lt",
    "params": [
      {"value": $idx_mouse, "params": []},
      {"value": "SPACE", "params": []}
    ]
  } |

  reduce [
    [14, "&msc", "SCRL_LEFT"],
    [15, "&mmv", "MOVE_UP"],
    [16, "&msc", "SCRL_RIGHT"],

    [31, "&mo", $idx_warp],
    [32, "&mo", $idx_fast],
    [33, "&mo", $idx_slow],

    [38, "&mo", $idx_slow],
    [39, "&mo", $idx_fast],
    [40, "&mo", $idx_warp],

    [51, "&mkp", "LCLK"],
    [52, "&mkp", "RCLK"],
    [57, "&mkp", "LCLK"],
    [58, "&mkp", "RCLK"]
  ][] as $b (.;
    .layers[$idx_mouse][$b[0]] = {
      "value": $b[1],
      "params": [
        {"value": $b[2], "params": []}
      ]
    }
  ) |

  # --- STEP 4: COMPREHENSIVE INPUT LISTENERS ---
  .inputListeners = [

    {
      "code": "&mmv_input_listener",
      "inputProcessors": [],
      "nodes": [
        {
          "code": "slow",
          "layers": [$idx_slow],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [1, 9]}
          ]
        },
        {
          "code": "fast",
          "layers": [$idx_fast],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [3, 1]}
          ]
        },
        {
          "code": "warp",
          "layers": [$idx_warp],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [12, 1]}
          ]
        }
      ]
    },

    {
      "code": "&msc_input_listener",
      "inputProcessors": [],
      "nodes": [
        {
          "code": "slow",
          "layers": [$idx_slow],
          "inputProcessors": [
            {"code": "&zip_scroll_scaler", "params": [1, 9]}
          ]
        },
        {
          "code": "fast",
          "layers": [$idx_fast],
          "inputProcessors": [
            {"code": "&zip_scroll_scaler", "params": [3, 1]}
          ]
        },
        {
          "code": "warp",
          "layers": [$idx_warp],
          "inputProcessors": [
            {"code": "&zip_scroll_scaler", "params": [12, 1]}
          ]
        }
      ]
    },

    {
      "code": "&cirque_lh_listener",
      "inputProcessors": [
        {"code": "&zip_xy_scaler", "params": [11, 12]},
        {"code": "&zip_xy_transform", "params": [["INPUT_TRANSFORM_Y_INVERT"]]},
        {"code": "&zip_xy_to_scroll_mapper", "params": []},
        {"code": "&zip_click_to_right_click_mapper", "params": []},
        {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
      ],
      "nodes": [
        {
          "code": "slow",
          "layers": [$idx_slow],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [5, 14]},
            {"code": "&zip_xy_transform", "params": [["INPUT_TRANSFORM_Y_INVERT"]]},
            {"code": "&zip_xy_to_scroll_mapper", "params": []},
            {"code": "&zip_click_to_right_click_mapper", "params": []},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        },
        {
          "code": "fast",
          "layers": [$idx_fast],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [3, 2]},
            {"code": "&zip_xy_transform", "params": [["INPUT_TRANSFORM_Y_INVERT"]]},
            {"code": "&zip_xy_to_scroll_mapper", "params": []},
            {"code": "&zip_click_to_right_click_mapper", "params": []},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        },
        {
          "code": "warp",
          "layers": [$idx_warp],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [13, 3]},
            {"code": "&zip_xy_transform", "params": [["INPUT_TRANSFORM_Y_INVERT"]]},
            {"code": "&zip_xy_to_scroll_mapper", "params": []},
            {"code": "&zip_click_to_right_click_mapper", "params": []},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        }
      ]
    },

    {
      "code": "&cirque_rh_listener",
      "inputProcessors": [
        {"code": "&zip_xy_scaler", "params": [5, 2]},
        {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
      ],
      "nodes": [
        {
          "code": "slow",
          "layers": [$idx_slow],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [1, 1]},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        },
        {
          "code": "fast",
          "layers": [$idx_fast],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [4, 1]},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        },
        {
          "code": "warp",
          "layers": [$idx_warp],
          "inputProcessors": [
            {"code": "&zip_xy_scaler", "params": [7, 1]},
            {"code": "&zip_temp_layer", "params": [$idx_mouse, 2000]}
          ]
        }
      ]
    }
  ]
)
